@implements IAsyncDisposable
@inject IJSRuntime JS

@ChildContent

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import",
            "./_content/sv-7a78a0835129480e8f930c7965289f23/Components/UserActivityTracker.razor.js");

        await _module.InvokeVoidAsync("initialize", _dotNetRef, TimeoutSeconds * 1000);
    }

    [JSInvokable]
    public async Task OnUserIdle()
    {
        if (_isIdle) return;
        _isIdle = true;
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnUserActive()
    {
        if (!_isIdle) return;
        _isIdle = false;
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

let dotNetRef = null;
let timeoutId = null;
let timeoutMs = 0;
let isIdle = false;

const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];

function onActivity() {
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync("OnUserActive");
    }
    resetTimer();
}

function resetTimer() {
    if (timeoutId !== null) {
        clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnUserIdle");
    }, timeoutMs);
}

export function initialize(ref, ms) {
    dotNetRef = ref;
    timeoutMs = ms;
    isIdle = false;

    for (const event of events) {
        document.addEventListener(event, onActivity, { passive: true });
    }
    resetTimer();
}

export function dispose() {
    if (timeoutId !== null) {
        clearTimeout(timeoutId);
        timeoutId = null;
    }
    for (const event of events) {
        document.removeEventListener(event, onActivity);
    }
    dotNetRef = null;
}

